def advanced_search(request):
    request_json = request.get_json(silent=True)
    request_args = request.args
    
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydatabase')
    db_host = os.environ.get('DB_HOST', '127.0.0.1')
    
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        base_query = request_args.get('query', 'SELECT * FROM users')
        
        if request_args.get('where_clause'):
            base_query += f" WHERE {request_args.get('where_clause')}"
        
        if request_args.get('join_table'):
            join_table = request_args.get('join_table')
            join_on = request_args.get('join_on', 'id')
            base_query += f" JOIN {join_table} ON {join_on}"
        
        if request_args.get('having'):
            base_query += f" HAVING {request_args.get('having')}"
        
        with connection.cursor() as cursor:
            cursor.execute(base_query)
            results = cursor.fetchall()
        
        return jsonify({
            'success': True,
            'data': results
        })
    
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500
    
    finally:
        connection.close()


def multi_table_search(request):
    request_json = request.get_json(silent=True)
    request_args = request.args
    
    connection = pymysql.connect(
        host=os.environ.get('DB_HOST', '127.0.0.1'),
        user=os.environ.get('DB_USER', 'root'),
        password=os.environ.get('DB_PASSWORD', ''),
        database=os.environ.get('DB_NAME', 'mydatabase'),
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        tables = request_args.get('tables', 'users,orders').split(',')
        results = {}
        
        for table in tables:
            query = f"SELECT * FROM {table}"
            
            if request_args.get(f'{table}_filter'):
                filter_clause = request_args.get(f'{table}_filter')
                query += f" WHERE {filter_clause}"
            
            with connection.cursor() as cursor:
                cursor.execute(query)
                results[table] = cursor.fetchall()
        
        return jsonify({
            'success': True,
            'data': results
        })
    
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500
    
    finally:
        connection.close()